import { test, expect } from '@playwright/test';

const BASE_URL = process.env.BASE_URL ?? 'http://localhost:3000';

test.describe('Checkout Page — medium-checkout', () => {
  test.afterEach(async ({ page }, testInfo) => {
    if (testInfo.status !== testInfo.expectedStatus) {
      const name = testInfo.title.replace(/[^a-z0-9]/gi, '-');
      await page.screenshot({ path: `evidence/${name}-FAIL.png`, fullPage: true });
    }
  });

  test('CHECKOUT-01 — Successful checkout with all required fields', async ({ page }) => {
    // Step 1: Navigate to checkout
    await page.goto(`${BASE_URL}/checkout`);

    // Step 2: Fill in shipping address
    await page.getByLabel('Full name').fill('Jane Smith');
    await page.getByLabel('Address line 1').fill('123 Main St');
    await page.getByLabel('City').fill('Springfield');
    await page.getByLabel('State / Province').selectOption('CA');
    await page.getByLabel('Postal code').fill('90210');

    // Step 3: Select payment method
    await page.getByRole('radio', { name: 'Credit / Debit Card' }).check();

    // Step 4: Accept terms
    await page.getByLabel(/I agree to the Terms/).check();

    // Step 5: Submit
    await page.getByRole('button', { name: 'Place Order' }).click();

    // [VERIFY] Confirm redirect to confirmation page
    await expect(page).not.toHaveURL(`${BASE_URL}/checkout`);
    await page.screenshot({ path: 'evidence/CHECKOUT-01-success.png' });
  });

  test('CHECKOUT-03 — Terms checkbox required before submit', async ({ page }) => {
    // Step 1: Navigate to checkout
    await page.goto(`${BASE_URL}/checkout`);

    // Step 2: Fill all required fields but leave terms unchecked
    await page.getByLabel('Full name').fill('Jane Smith');
    await page.getByLabel('Address line 1').fill('123 Main St');
    await page.getByLabel('City').fill('Springfield');
    await page.getByLabel('State / Province').selectOption('CA');
    await page.getByLabel('Postal code').fill('90210');
    await page.getByRole('radio', { name: 'Credit / Debit Card' }).check();
    // Terms checkbox intentionally left unchecked

    // Step 3: Attempt submit
    await page.getByRole('button', { name: 'Place Order' }).click();

    // [VERIFY] Confirm terms error is shown and form not submitted
    const termsError = page.locator('#terms-error');
    await termsError.waitFor({ state: 'visible' });
    await expect(page).toHaveURL(`${BASE_URL}/checkout`);
    await page.screenshot({ path: 'evidence/CHECKOUT-03-terms.png' });
  });

  test('CHECKOUT-09 — Keyboard navigation covers all interactive elements', async ({ page }) => {
    // Step 1: Load checkout page
    await page.goto(`${BASE_URL}/checkout`);

    // Step 2: Tab to Full name (first focusable field)
    await page.keyboard.press('Tab');
    // [VERIFY] Confirm full name input is first focusable element
    await expect(page.getByLabel('Full name')).toBeFocused();

    await page.screenshot({ path: 'evidence/CHECKOUT-09-keyboard.png' });
  });
});
